try {
    $pdo = new PDO("mysql:host=" . USER_DB_HOST . ";dbname=" . USER_DB_NAME . ";charset=" . USER_DB_CHARSET, USER_DB_USER, USER_DB_PASSWORD);
    $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

    // SET SQL_MODE
    $pdo->exec("SET SQL_MODE = 'NO_AUTO_VALUE_ON_ZERO';");

    $sql = "
    CREATE TABLE IF NOT EXISTS `sales` (
        `id` int(11) NOT NULL AUTO_INCREMENT,
        `platform` int(11) NOT NULL COMMENT '0-Internal, 1-warriorplus',
        `internal_product_id` int(11) NOT NULL COMMENT '0=test, 1=Credit',
        `pack_name` text NOT NULL,
        `name` text NOT NULL,
        `email` text NOT NULL,
        `buyer_ip` text NOT NULL,
        `purchase_date` datetime NOT NULL,
        `cancel_date` datetime NOT NULL,
        `txid` text NOT NULL,
        `item_number` text NOT NULL,
        `item_name` text NOT NULL,
        `credits` int(11) NOT NULL,
        `user_id` int(11) NOT NULL,
        `sale_amount` text NOT NULL,
        `sale_currency` text NOT NULL,
		`type` int(11) NOT NULL COMMENT '0=one time sale, 1=recurring sale',
        PRIMARY KEY (`id`)
    ) DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
    ";

    $pdo->exec($sql);

    $stmt = $pdo->prepare("SHOW COLUMNS FROM `users` LIKE 'user_credits'");
    $stmt->execute();
    $columnExists = $stmt->fetch(PDO::FETCH_ASSOC);

    if (!$columnExists) {
        $alterSql = "ALTER TABLE `users` ADD `user_credits` INT(11) NOT NULL DEFAULT 0;";
        $pdo->exec($alterSql);
    }

} catch (PDOException $e) {
    echo "Error: " . $e->getMessage();
}

$pdo = null;

